args.sparql:
SELECT ?winner ?winnerLabel WHERE {
  ?award wdt:P31 wd:Q1773951 ;  # Empire Award for Best Actor category
         wdt:P3455 ?winner ;
         wdt:P585 ?awardDate.
  FILTER(YEAR(?awardDate) = 2015).
  ?winner rdfs:label ?winnerLabel.
  FILTER(LANG(?winnerLabel) = 'en').
}

SELECT ?actor ?actorLabel WHERE {
  ?award wdt:P31 wd:Q1773951 ;
         wdt:P3455 ?actor .
  ?actor wdt:P161 wd:Q16970789 .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
} LIMIT 1

